def compute_score() -> tuple[str, float]:
    import re
    from pptx import Presentation
    def norm(s):
        return re.sub(r'\s+', ' ', s).strip().lower()
    old_title = norm("REVISITING CLASSICAL SOCIAL EXPERIMENTS")
    new_title = norm("EXPLORING CLASSICAL SOCIAL EXPERIMENTS")
    prs = Presentation(modified_ppt_path)
    found_old = False
    found_new = False
    for shape in prs.slides[0].shapes:
        if shape.has_text_frame:
            for paragraph in shape.text_frame.paragraphs:
                text = norm(paragraph.text)
                if text == old_title:
                    found_old = True
                if text == new_title:
                    found_new = True
    if found_new:
        return "Title was changed to the correct new text.", 1.0
    elif found_old:
        return "Title was not changed.", 0.0
    else:
        return "Neither the old nor the new title was found. Possible error in modification.", 0.0

