    # Only allow one modified slide, and only the title text should be changed.
    # No slides should be added or removed.
    if ppt_diff.added_slides or ppt_diff.removed_slides:
        return "Slides were added or removed, which is extraneous.", 0.0
    if len(ppt_diff.modified_slides) == 0:
        return "No slides were modified.", 0.0
    if len(ppt_diff.modified_slides) > 1:
        return "More than one slide was modified.", 0.0
    # Check that only the title text was changed
    old_slide, new_slide = ppt_diff.modified_slides[0]
    # If slide number or layout changed, that's extraneous
    if old_slide.slide_number != new_slide.slide_number or old_slide.layout_type != new_slide.layout_type or old_slide.element_count != new_slide.element_count or old_slide.notes != new_slide.notes:
        return "Slide metadata other than title text was changed.", 0.0
    return "No extraneous slide additions, removals, or modifications detected.", 1.0

